#!/usr/bin/env python3
import argparse
import json
import re
from pathlib import Path

import pandas as pd


DEFAULT_INPUTS = [
    "/mnt/workspace/luofuwen/datasets/PMC-Case-Report/raw/train-00000-of-00002.parquet",
    "/mnt/workspace/luofuwen/datasets/PMC-Case-Report/raw/train-00001-of-00002.parquet",
]
DEFAULT_OUTPUT = (
    "/mnt/workspace/luofuwen/datasets/PMC-Case-Report/diagnosis_treatment_matches.json"
)

SENTENCE_SPLIT_RE = re.compile(r"(?<=[\.\?\!;])\s+")
SPACE_RE = re.compile(r"\s+")

DIAGNOSIS_PATTERNS = [
    re.compile(
        r"\b(?:was|were|is|are|later|subsequently)?\s*diagnosed with\s+"
        r"(?P<entity>[^.;:,]+)",
        re.IGNORECASE,
    ),
    re.compile(
        r"\bdiagnosis\s+(?:of|was|revealed|confirmed as)\s+(?P<entity>[^.;:,]+)",
        re.IGNORECASE,
    ),
    re.compile(
        r"\b(?:found to have|found to be suffering from|confirmed to have|noted to have)\s+"
        r"(?P<entity>[^.;:,]+)",
        re.IGNORECASE,
    ),
    re.compile(
        r"\b(?:consistent with|compatible with|suggestive of|indicative of)\s+"
        r"(?P<entity>[^.;:,]+)",
        re.IGNORECASE,
    ),
    re.compile(
        r"\b(?:revealed|showed|demonstrated|confirmed)\s+"
        r"(?P<entity>(?:an?|the)?\s*[^.;:,]{3,80}?(?:disease|syndrome|cancer|carcinoma|tumou?r|tumor|"
        r"infection|pneumonia|sepsis|diabetes|colitis|hepatitis|anemia|lymphoma|leukemia|sarcoma|"
        r"failure|injury|thrombosis|embolism|abscess|ulcer|cirrhosis|arthritis|myeloma|stenosis|"
        r"occlusion|deficiency|malignancy|AIHA|IBD|COPD|ARDS|COVID-19))",
        re.IGNORECASE,
    ),
]

TREATMENT_PATTERNS = [
    re.compile(
        r"\b(?:treated with|managed with|started on|placed on|given|received|administered)\s+"
        r"(?P<entity>[^.;:]+)",
        re.IGNORECASE,
    ),
    re.compile(
        r"\b(?:underwent|underwent urgent|underwent emergent)\s+"
        r"(?P<entity>[^.;:]+)",
        re.IGNORECASE,
    ),
    re.compile(
        r"\b(?:therapy|treatment|management)\s+(?:included|consisted of|was|with)\s+"
        r"(?P<entity>[^.;:]+)",
        re.IGNORECASE,
    ),
]

NEGATIVE_CONTEXT_RE = re.compile(
    r"\b(?:no|not|without|rule out|ruled out|negative for|free of|denied)\b",
    re.IGNORECASE,
)
GENERIC_ENTITY_RE = re.compile(
    r"^(?:a|an|the|this|that|these|those|his|her|their)\s+",
    re.IGNORECASE,
)
STOP_TAIL_RE = re.compile(
    r"\b(?:with|for|because of|due to|after|before|and|but|while|when|whereas)\b.*$",
    re.IGNORECASE,
)
NON_SPECIFIC_RE = re.compile(
    r"\b(?:diagnosis|treatment|therapy|management|medication|medicine|drugs?|care|workup|evaluation|"
    r"symptoms?|complaints?|condition|disease process|issue|problem|abnormality|finding|history)\b",
    re.IGNORECASE,
)
LIKELY_TREATMENT_WORD_RE = re.compile(
    r"\b(?:mg|mcg|g|ml|tablet|dose|daily|bid|tid|qid|intravenous|oral|iv|antibiotic|steroid|"
    r"prednisone|methylprednisolone|hydrocortisone|chemotherapy|radiotherapy|resection|surgery|"
    r"transplantation|transplant|aspirin|heparin|warfarin|insulin|ventilation|dialysis|drainage|"
    r"embolization|immunotherapy|antiviral|antifungal)\b",
    re.IGNORECASE,
)


def normalize_text(text: str) -> str:
    text = text.replace("\xa0", " ")
    text = SPACE_RE.sub(" ", text)
    return text.strip()


def split_sentences(text: str) -> list[str]:
    text = normalize_text(text)
    if not text:
        return []
    return [s.strip() for s in SENTENCE_SPLIT_RE.split(text) if s.strip()]


def clean_entity(raw: str) -> str:
    entity = normalize_text(raw)
    entity = entity.strip(" ,:;.-")
    entity = GENERIC_ENTITY_RE.sub("", entity)
    entity = STOP_TAIL_RE.sub("", entity).strip(" ,:;.-")
    entity = re.sub(r"\([^)]*\)", "", entity).strip(" ,:;.-")
    entity = re.sub(r"\s{2,}", " ", entity)
    return entity


def has_negative_context(sentence: str, match_start: int) -> bool:
    prefix = sentence[max(0, match_start - 40) : match_start]
    return bool(NEGATIVE_CONTEXT_RE.search(prefix))


def looks_specific_diagnosis(entity: str) -> bool:
    if len(entity) < 3 or len(entity) > 120:
        return False
    if NON_SPECIFIC_RE.fullmatch(entity.lower()):
        return False
    letters = re.findall(r"[A-Za-z]", entity)
    return len(letters) >= 2


def looks_specific_treatment(entity: str) -> bool:
    if len(entity) < 3 or len(entity) > 160:
        return False
    if NON_SPECIFIC_RE.fullmatch(entity.lower()):
        return False
    return bool(LIKELY_TREATMENT_WORD_RE.search(entity) or len(entity.split()) >= 2)


def extract_from_sentence(sentence: str) -> list[dict]:
    findings = []
    for pattern in DIAGNOSIS_PATTERNS:
        for match in pattern.finditer(sentence):
            if has_negative_context(sentence, match.start()):
                continue
            entity = clean_entity(match.group("entity"))
            if looks_specific_diagnosis(entity):
                findings.append(
                    {
                        "type": "diagnosis",
                        "entity": entity,
                        "evidence": sentence,
                    }
                )
    for pattern in TREATMENT_PATTERNS:
        for match in pattern.finditer(sentence):
            if has_negative_context(sentence, match.start()):
                continue
            entity = clean_entity(match.group("entity"))
            if looks_specific_treatment(entity):
                findings.append(
                    {
                        "type": "treatment",
                        "entity": entity,
                        "evidence": sentence,
                    }
                )
    deduped = []
    seen = set()
    for item in findings:
        key = (item["type"], item["entity"].lower(), item["evidence"])
        if key not in seen:
            seen.add(key)
            deduped.append(item)
    return deduped


def extract_from_context(context: str) -> list[dict]:
    all_findings = []
    seen = set()
    for sentence in split_sentences(context):
        for finding in extract_from_sentence(sentence):
            key = (finding["type"], finding["entity"].lower(), finding["evidence"])
            if key not in seen:
                seen.add(key)
                all_findings.append(finding)
    return all_findings


def process_file(path: str) -> tuple[list[dict], int]:
    df = pd.read_parquet(path, columns=["PMC_id", "context"])
    matches = []
    matched_rows = 0
    for row_idx, row in enumerate(df.itertuples(index=False, name=None)):
        pmc_id, context = row
        if not isinstance(context, str) or not context.strip():
            continue
        findings = extract_from_context(context)
        if not findings:
            continue
        matched_rows += 1
        matches.append(
            {
                "source_file": Path(path).name,
                "row_index": int(row_idx),
                "PMC_id": pmc_id,
                "context": normalize_text(context),
                "findings": findings,
            }
        )
    return matches, matched_rows


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Extract rows whose context contains explicit diagnosis or treatment information."
    )
    parser.add_argument(
        "--inputs",
        nargs="+",
        default=DEFAULT_INPUTS,
        help="Input parquet files.",
    )
    parser.add_argument(
        "--output",
        default=DEFAULT_OUTPUT,
        help="Output JSON path.",
    )
    args = parser.parse_args()

    all_matches = []
    per_file_counts = {}
    total_rows = 0

    for input_path in args.inputs:
        matches, matched_rows = process_file(input_path)
        all_matches.extend(matches)
        per_file_counts[Path(input_path).name] = matched_rows
        total_rows += matched_rows

    output_path = Path(args.output)
    output_path.parent.mkdir(parents=True, exist_ok=True)
    with output_path.open("w", encoding="utf-8") as f:
        json.dump(
            {
                "matched_rows": total_rows,
                "per_file_counts": per_file_counts,
                "records": all_matches,
            },
            f,
            ensure_ascii=False,
            indent=2,
        )

    print(f"Matched rows: {total_rows}")
    print(f"Output written to: {output_path}")
    for name, count in per_file_counts.items():
        print(f"{name}: {count}")

